func solve(s: String, k: Int64) -> String {
    var current: String = ""

    for char in s {
        if char >= "a" && char <= "z" {
            current.append(char)
        } else if char == "*" {
            if !current.isEmpty {
                current.removeLast()
            }
        } else if char == "#" {
            current = current + current
        } else if char == "%" {
            current = String(current.reversed())
        }
    }

    let totalLength = Int64(current.count)
    if k < 0 || k >= totalLength {
        return "."
    }

    let index = String.Index(utf16Offset: Int(k), in: current)
    return String(current[index])
}
```

