func solve(s: String, k: Int64) -> String {
    let n = s.count
    if n == 0 {
        return k == 0 && n != 0 ? String(s.first!) : "."
    }

    var lens = [Int64](repeating: 0, count: n+1)
    var curr: Int64 = 0
    let sArr = Array(s)
    for i in 0..<n {
        let c = sArr[i]
        switch c {
        case "a"..."z":
            curr += 1
        case "*":
            if curr > 0 {
                curr -= 1
            }
        case "#":
            curr = curr * 2
        case "%":
            break
        default:
            break
        }
        lens[i+1] = curr
    }

    let totalLength = lens[n]
    var k0 = k
    if k0 < 0 || k0 >= totalLength {
        return "."
    }

    for i in (0..<n).reversed() {
        let c = sArr[i]
        let L = lens[i+1]
        if k0 >= L {
            return "."
        }

        switch c {
        case "a"..."z":
            if k0 == L - 1 {
                return String(c)
            } else {
                if curr > 0 {
                    if k0 == lens[i] {
                        return "."
                    }
                }
            }
        case "*":
            let prevLen = lens[i] 
            if k0 == prevLen - 1 {
                return "."
            } else if k0 >= prevLen {
                return "."
            }
        case "#":
            let prevLen = lens[i] 
            if prevLen <= 0 {
                continue
            }
            if k0 >= prevLen {
                k0 -= prevLen
            }
        case "%":
            k0 = L - 1 - k0
        default:
            break
        }
    }

    return "."
}
```

