func solve(s: String, k: Int64) -> String {
    let n = s.count
    if n == 0 {
        return "."
    }
    let chars = Array(s)
    var lens = [Int64](repeating: 0, count: n+1)
    lens[0] = 0
    for i in 0..<n {
        let c = chars[i]
        if c >= "a" && c <= "z" {
            lens[i+1] = lens[i] + 1
        } else if c == "*" {
            lens[i+1] = max(0, lens[i] - 1)
        } else if c == "#" {
            lens[i+1] = lens[i] * 2
        } else if c == "%" {
            lens[i+1] = lens[i]
        }
    }

    let finalLength = lens[n]
    if k < 0 || k >= finalLength {
        return "."
    }

    var current_k = k
    var i = n - 1
    while i >= 0 {
        let c = chars[i]
        let current_length = lens[i+1]
        let prev_length = lens[i]

        if current_k >= current_length {
            break
        }

        if c >= "a" && c <= "z" {
            if current_k == current_length - 1 {
                return String(c)
            }
        } else if c == "*" {
            // no operation, k remains the same
        } else if c == "#" {
            if prev_length == 0 {
                break
            }
            current_k %= prev_length
        } else if c == "%" {
            current_k = prev_length - 1 - current_k
        }

        i -= 1
    }

    return "."
}
```

