func solve(s: String, k: Int64) -> String {
    let arr = Array(s)
    var total: Int64 = 0

    for c in arr {
        if c >= "a" && c <= "z" {
            total += 1
        } else if c == "*" {
            if total > 0 {
                total -= 1
            }
        } else if c == "#" {
            total *= 2
        }
    }

    if k < 0 || k >= total {
        return "."
    }

    var current_k = k
    var current_len = total

    for i in (0..<arr.count).reversed() {
        let c = arr[i]
        if c >= "a" && c <= "z" {
            if current_k == current_len - 1 {
                return String(c)
            } else {
                current_len -= 1
            }
        } else if c == "*" {
            current_len += 1
        } else if c == "#" {
            let half = current_len / 2
            if current_k >= half {
                current_k -= half
            }
            current_len = half
        } else if c == "%" {
            current_k = current_len - 1 - current_k
        }
    }

    return "."
}
```

